import { createRoot } from "react-dom/client";
import { useEffect, useRef, useState } from "react";
import "./style.css";

// ponytail: native Canvas2D + rAF, one component, zero deps added.
function OrbitField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [paused, setPaused] = useState(false);
  const pausedRef = useRef(paused);
  pausedRef.current = paused;

  useEffect(() => {
    const canvas = canvasRef.current!;
    const ctx = canvas.getContext("2d")!;
    const reduce = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

    let w = 0, h = 0;
    const resize = () => {
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      w = canvas.clientWidth; h = canvas.clientHeight;
      canvas.width = Math.floor(w * dpr);
      canvas.height = Math.floor(h * dpr);
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      draw();
    };

    const rings = [60, 110, 170, 230];
    const parts = rings.flatMap((r, i) => {
      const n = 6 + i * 3;
      return Array.from({ length: n }, (_, k) => ({
        r,
        speed: (i % 2 ? 1 : -1) * (0.3 + (k % 3) * 0.1),
        a: (k / n) * Math.PI * 2,
        size: 2 + (k % 2),
        hue: (r * 2 + k * 20) % 360,
      }));
    });

    const ptr = { x: 0, y: 0, tx: 0, ty: 0 };
    const onMove = (e: PointerEvent) => {
      const rect = canvas.getBoundingClientRect();
      ptr.tx = e.clientX - rect.left - w / 2;
      ptr.ty = e.clientY - rect.top - h / 2;
      if (reduce) draw();
    };
    const onLeave = () => { ptr.tx = 0; ptr.ty = 0; if (reduce) draw(); };

    let raf = 0;
    let t = 0;
    function draw() {
      t += 1;
      ptr.x += (ptr.tx - ptr.x) * 0.1;
      ptr.y += (ptr.ty - ptr.y) * 0.1;

      ctx.fillStyle = "#0b1020";
      ctx.fillRect(0, 0, w, h);

      const cx = w / 2 + ptr.x, cy = h / 2 + ptr.y;
      const glow = ctx.createRadialGradient(cx, cy, 0, cx, cy, 50);
      glow.addColorStop(0, "rgba(120,180,255,0.8)");
      glow.addColorStop(1, "rgba(120,180,255,0)");
      ctx.fillStyle = glow;
      ctx.fillRect(cx - 50, cy - 50, 100, 100);

      for (const p of parts) {
        const px = cx + Math.cos(p.a) * p.r;
        const py = cy + Math.sin(p.a) * p.r;
        ctx.beginPath();
        ctx.arc(px, py, p.size, 0, Math.PI * 2);
        ctx.fillStyle = `hsl(${(p.hue + t * 0.5) % 360} 80% 70%)`;
        ctx.fill();
        if (!pausedRef.current && !reduce) p.a += p.speed * 0.02;
      }
    }

    resize();
    window.addEventListener("resize", resize);
    canvas.addEventListener("pointermove", onMove);
    canvas.addEventListener("pointerleave", onLeave);

    if (!reduce) {
      const loop = () => { draw(); raf = requestAnimationFrame(loop); };
      loop();
    }

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
      canvas.removeEventListener("pointermove", onMove);
      canvas.removeEventListener("pointerleave", onLeave);
    };
  }, []);

  return (
    <main style={{ position: "fixed", inset: 0, background: "#0b1020" }}>
      <canvas
        ref={canvasRef}
        style={{ width: "100%", height: "100%", display: "block", touchAction: "none" }}
        aria-label="Orbit field animation"
      />
      <button
        onClick={() => setPaused(p => !p)}
        aria-pressed={paused}
        aria-label={paused ? "Resume orbit animation" : "Pause orbit animation"}
        style={{
          position: "absolute", top: 12, right: 12,
          padding: "8px 14px", borderRadius: 8,
          border: "1px solid rgba(255,255,255,0.4)",
          background: "rgba(0,0,0,0.5)", color: "#fff",
          font: "inherit", cursor: "pointer",
        }}
      >
        {paused ? "Resume" : "Pause"}
      </button>
    </main>
  );
}

createRoot(document.getElementById("root")!).render(<OrbitField />);
